{"file_path": "/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/PackageNameRuleNordicCharsTest.kt", "content": "package com.pinterest.ktlint.ruleset.standard

import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Test

class PackageNameRuleNordicCharsTest {
    private val packageNameRuleAssertThat = assertThatRule { PackageNameRule() }

    @Test
    fun `Given a package name containing Nordic characters then do not return lint errors`() {
        val code =
            """
            package føø.bår.bæz
            """.trimIndent()
        packageNameRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a package name containing various Nordic characters (å, ä, ö, æ, ø) then do not return lint errors`() {
        val code =
            """
            package tëst.nørdiç.chàrs.åäöæø
            """.trimIndent()
        packageNameRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a package name with lowercase Nordic characters then do not return lint errors`() {
        val code =
            """
            package løwércåsé
            """.trimIndent()
        packageNameRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a package name starting with Nordic character then do not return lint errors`() {
        val code =
            """
            package øtest.bar
            """.trimIndent()
        packageNameRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a package name with underscore then return lint error`() {
